                data-index={index}
                role="option"
                aria-selected={isHighlighted}
                onClick={() => handleSuggestionClick(suggestion)}
                className={`w-full text-left px-3 py-2 text-xs transition-colors ${
                  isHighlighted
                    ? 'bg-accent-blue/10 text-accent-blue'
                    : 'text-text-light-primary dark:text-text-dark-primary hover:bg-surface-light-elevated dark:hover:bg-neutral-800'
                }`}
              >
                {display}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

